import{_ as l,o as r,c as e,a0 as o}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"📊 網頁儀表板使用與管理指南","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Dashboard.md","filePath":"Web-Dashboard.md"}'),i={name:"Web-Dashboard.md"};function t(n,a,s,d,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="📊-網頁儀表板使用與管理指南" tabindex="-1">📊 網頁儀表板使用與管理指南 <a class="header-anchor" href="#📊-網頁儀表板使用與管理指南" aria-label="Permalink to &quot;📊 網頁儀表板使用與管理指南&quot;">​</a></h1><p>本系統提供全功能網頁儀表板，支援玩家跨平台即時查詢伺服器經濟、個人簽到狀態、領地細部權限、密碼安全箱名冊與收發離線快遞。</p><hr><h2 id="🔑-1-登入方式與帳號綁定" tabindex="-1">🔑 1. 登入方式與帳號綁定 <a class="header-anchor" href="#🔑-1-登入方式與帳號綁定" aria-label="Permalink to &quot;🔑 1. 登入方式與帳號綁定&quot;">​</a></h2><ol><li><strong>官方 Discord 帳號登入</strong>： <ul><li>點選網頁右上角的 <strong><code>[ 以 Discord 帳號登入 ]</code></strong> 按鈕。</li><li>登入成功後，系統會自動尋找您綁定的 Minecraft 角色資訊。</li><li>若您的帳號尚未綁定，網頁會彈出提示，請您先進入遊戲內執行 <code>/discord link</code> 獲取驗證碼。</li></ul></li><li><strong>測試登入 (Developer Bypass)</strong>： <ul><li>用於本機環境測試。直接在登入框輸入您的 Minecraft 玩家名稱（如 <code>Yanggu</code>）即可直接登入以進行功能預覽與權限修改。</li></ul></li></ol><hr><h2 id="🏠-2-首頁功能看板" tabindex="-1">🏠 2. 首頁功能看板 <a class="header-anchor" href="#🏠-2-首頁功能看板" aria-label="Permalink to &quot;🏠 2. 首頁功能看板&quot;">​</a></h2><p>登入後，首頁提供以下核心資訊：</p><h3 id="a-全服經濟概況統計" tabindex="-1">A. 全服經濟概況統計 <a class="header-anchor" href="#a-全服經濟概況統計" aria-label="Permalink to &quot;A. 全服經濟概況統計&quot;">​</a></h3><ul><li><strong>💰 總流通金幣</strong>：全服玩家帳戶中所持有的金幣總額。</li><li><strong>🏛️ 累計收繳稅額</strong>：顯示商店交易累計已被系統回收並銷毀的 5% 印花稅金幣總量。</li><li><strong>🏪 營運中胸口商店</strong>：當前全伺服器正在營業的玩家商店總數量。</li></ul><h3 id="b-📅-今日每日任務-daily-tasks" tabindex="-1">B. 📅 今日每日任務 (Daily Tasks) <a class="header-anchor" href="#b-📅-今日每日任務-daily-tasks" aria-label="Permalink to &quot;B. 📅 今日每日任務 (Daily Tasks)&quot;">​</a></h3><ul><li>顯示今日隨機產生的 1 個擊殺任務與 1 個挖掘任務。</li><li>登入後可直接看見您當前的任務完成進度百分比（如 <code>進度: 3 / 5 (60%)</code>）與完成狀態。</li></ul><h3 id="c-📅-個人簽到與抽獎福利" tabindex="-1">C. 📅 個人簽到與抽獎福利 <a class="header-anchor" href="#c-📅-個人簽到與抽獎福利" aria-label="Permalink to &quot;C. 📅 個人簽到與抽獎福利&quot;">​</a></h3><ul><li><strong>連續簽到天數</strong>：顯示您的每日連續簽到天數。</li><li><strong>累計簽到次數</strong>：顯示總簽到次數。</li><li><strong>擁有抽獎鑰匙</strong>：顯示目前帳戶持有的幸運抽獎鑰匙數量。</li><li><strong>上次簽到時間</strong>：顯示您最後一次簽到的日期與時間。</li></ul><h3 id="d-📬-離線快遞收發信箱" tabindex="-1">D. 📬 離線快遞收發信箱 <a class="header-anchor" href="#d-📬-離線快遞收發信箱" aria-label="Permalink to &quot;D. 📬 離線快遞收發信箱&quot;">​</a></h3><ul><li>列出所有以您為收件人或寄件人的離線郵件快遞狀態。</li><li>顯示寄送物品（如 <code>IRON_INGOT</code>）、數量、時間以及寄件人。</li><li>顯示快遞包裹的狀態： <ul><li><strong>✓ 已送達 (Delivered)</strong>：表示收件人已上線接收金幣或物品。</li><li><strong>⏰ 離線暫存 (Pending)</strong>：表示收件人目前離線，包裹正儲存於伺服器快遞保管庫中。</li></ul></li></ul><h3 id="e-🏆-伺服器財富富豪榜" tabindex="-1">E. 🏆 伺服器財富富豪榜 <a class="header-anchor" href="#e-🏆-伺服器財富富豪榜" aria-label="Permalink to &quot;E. 🏆 伺服器財富富豪榜&quot;">​</a></h3><ul><li>顯示全服金幣餘額前 10 名的玩家排行榜，並顯示各玩家的 Minecraft 皮膚頭像。</li></ul><h3 id="f-🛒-即時交易動態日誌" tabindex="-1">F. 🛒 即時交易動態日誌 <a class="header-anchor" href="#f-🛒-即時交易動態日誌" aria-label="Permalink to &quot;F. 🛒 即時交易動態日誌&quot;">​</a></h3><ul><li>只要遊戲內有玩家買賣交易成功，網頁就會在不重新整理的狀態下，即時更新並推播顯示成交金額、買家、賣家與商品數量，實現無延遲的交易動態監控。</li></ul><hr><h2 id="🔍-3-商店瀏覽器-shop-explorer" tabindex="-1">🔍 3. 商店瀏覽器 (Shop Explorer) <a class="header-anchor" href="#🔍-3-商店瀏覽器-shop-explorer" aria-label="Permalink to &quot;🔍 3. 商店瀏覽器 (Shop Explorer)&quot;">​</a></h2><ul><li>羅列出全伺服器目前所有營業中的玩家商店。</li><li>支援依據物品名稱進行關鍵字搜尋，以及依照價格（由低到高/由高到低）或庫存量進行排序。</li><li>可直接點選座標複製 <strong><code>/shop control</code> 傳送指令</strong>，在遊戲內貼上即可直接傳送至該店面。</li></ul><hr><h2 id="🛡️-4-領地防護與密碼箱管理" tabindex="-1">🛡️ 4. 領地防護與密碼箱管理 <a class="header-anchor" href="#🛡️-4-領地防護與密碼箱管理" aria-label="Permalink to &quot;🛡️ 4. 領地防護與密碼箱管理&quot;">​</a></h2><p>此分頁提供登入玩家管理個人的安全資產：</p><h3 id="a-領地權限管理-claims-manager" tabindex="-1">A. 領地權限管理 (Claims Manager) <a class="header-anchor" href="#a-領地權限管理-claims-manager" aria-label="Permalink to &quot;A. 領地權限管理 (Claims Manager)&quot;">​</a></h3><ul><li>列出所有您擁有的保護領地座標範圍。</li><li>支援針對指定領地，為其他玩家指派與設定以下權限： <ul><li><strong>Build (建造)</strong></li><li><strong>Break (破壞)</strong></li><li><strong>Containers (容器)</strong></li><li><strong>Interact (互動)</strong></li></ul></li></ul><h3 id="b-密碼鎖安全名冊-lockbox-manager" tabindex="-1">B. 密碼鎖安全名冊 (Lockbox Manager) <a class="header-anchor" href="#b-密碼鎖安全名冊-lockbox-manager" aria-label="Permalink to &quot;B. 密碼鎖安全名冊 (Lockbox Manager)&quot;">​</a></h3><ul><li>顯示您目前所持有的全部密碼箱確切座標。</li><li>顯示已通過 <code>/padlock grant</code> 授權，有權直接開啟此箱子的玩家白名單。</li></ul>',30)])])}const b=l(i,[["render",t]]);export{g as __pageData,b as default};
